function numeroPorExtenso(num) {
  const unidades = [
    '', 'Um', 'Dois', 'Três', 'Quatro',
    'Cinco', 'Seis', 'Sete', 'Oito', 'Nove'
  ];

  const especiais = [
    'Dez', 'Onze', 'Doze', 'Treze', 'Quatorze',
    'Quinze', 'Dezesseis', 'Dezessete', 'Dezoito', 'Dezenove'
  ];

  const dezenas = [
    '', '', 'Vinte', 'Trinta', 'Quarenta',
    'Cinquenta', 'Sessenta', 'Setenta', 'Oitenta', 'Noventa'
  ];

  function converter(n) {
    if (n < 10) return unidades[n];
    if (n < 20) return especiais[n - 10];

    const dezena = Math.floor(n / 10);
    const unidade = n % 10;

    return dezenas[dezena] + (unidade ? ' e ' + unidades[unidade] : '');
  }

  return converter(num);
}

const percentual = $('Webhook').first().json.body.percentual_cliente;

return [{
  percentual_cliente_formatado:
    `${percentual}% (${numeroPorExtenso(percentual)} Por Cento)`
}];

